import java.sql.ResultSet;
import java.sql.SQLException;
import sailpoint.object.*;
import java.sql.*;
import java.sql.SQLException;
import sailpoint.tools.Message; 
import sailpoint.tools.Util;



public int checkRecordExistance(String c1value, String c2value , String c3value){

  log.error("......Entering into checkRecordExistance method.....");

  Connection connection = null;
  PreparedStatement preparedStatement = null;
  ResultSet resultSet = null;

  String dbUrl = "jdbc:mysql://localhost:3306/test"; 
  String dbUsername = "root"; 
  String dbPassword = "root"; 

  int existcount = 0;

  try{

    Class.forName("com.mysql.cj.jdbc.Driver");
    connection = DriverManager.getConnection(dbUrl, dbUsername, dbPassword);


    String existanceCheckQuery="SELECT COUNT(*) FROM test.columns_data WHERE c1 = ? AND c2 = ? AND c3 = ?";

    preparedStatement = connection.prepareStatement(existanceCheckQuery);
    preparedStatement.setString(1, c1value);
    preparedStatement.setString(2, c2value);
    preparedStatement.setString(3, c3value);

    resultSet = preparedStatement.executeQuery();

    if (resultSet.next()) {

      existcount = resultSet.getInt(1);

    }

    formModel.put("existcount",existcount);

  }catch (SQLException e) {
    e.printStackTrace();
  }finally {
    if (resultSet != null) {
      try {
        resultSet.close();
      } catch (SQLException e) {
        e.printStackTrace();
      }
    }
    if (preparedStatement != null) {
      try {
        preparedStatement.close();
      } catch (SQLException e) {
        e.printStackTrace();
      }
    }
    if (connection != null) {
      try {
        connection.close();
      } catch (SQLException e) {
        e.printStackTrace();
      }
    }
  }


  log.error("......Exiting from checkRecordExistance method.....");
  return existcount;
}






